161	// Each MCP session gets its own transport + server pair.
162	const sessions = new Map<string, StreamableHTTPServerTransport>();
163	
164	async function getOrCreateSession(
165	  sessionId: string | undefined,
166	): Promise<StreamableHTTPServerTransport | null> {
167	  if (sessionId) {
168	    return sessions.get(sessionId) ?? null;
169	  }
170	  // New session
171	  const transport = new StreamableHTTPServerTransport({
172	    sessionIdGenerator: () => randomUUID(),
173	  });
174	  const mcpServer = createMcpServer();
175	  await mcpServer.connect(transport);
176	  transport.onclose = () => {
177	    if (transport.sessionId) sessions.delete(transport.sessionId);
178	  };
179	  if (transport.sessionId) {
180	    sessions.set(transport.sessionId, transport);
181	  }
182	  return transport;
183	}
