185	// ─── HTTP server ──────────────────────────────────────────────────────────────
186	
187	function isAuthorized(req: { headers: { authorization?: string } }): boolean {
188	  if (!BEARER_TOKEN) return true;
189	  return req.headers.authorization === `Bearer ${BEARER_TOKEN}`;
190	}
