192	const httpServer = createServer(async (req, res) => {
193	  res.setHeader("Access-Control-Allow-Origin", "*");
194	  res.setHeader("Access-Control-Allow-Methods", "GET, POST, DELETE, OPTIONS");
195	  res.setHeader("Access-Control-Allow-Headers", "Authorization, Content-Type, Mcp-Session-Id");
196	
197	  if (req.method === "OPTIONS") {
198	    res.writeHead(204);
199	    res.end();
200	    return;
201	  }
202	
203	  const url = new URL(req.url ?? "/", `http://localhost`);
204	
205	  // Health check — no auth required
206	  if (url.pathname === "/health" && req.method === "GET") {
207	    res.writeHead(200, { "Content-Type": "application/json" });
208	    res.end(
209	      JSON.stringify({
210	        status: "ok",
211	        service: "nas-mcp",
212	        sessions: sessions.size,
213	        read_tools: enabledRead.size,
214	        write_tools: enabledWrite.size,
215	      }),
216	    );
217	    return;
218	  }
219	
220	  if (!isAuthorized(req as Parameters<typeof isAuthorized>[0])) {
221	    res.writeHead(401, { "Content-Type": "application/json" });
222	    res.end(JSON.stringify({ error: "Unauthorized" }));
223	    return;
224	  }
225	
226	  // MCP endpoint — handles both Streamable HTTP (POST/GET) and session routing
227	  if (url.pathname === "/sse" || url.pathname === "/mcp") {
228	    const sessionId = req.headers["mcp-session-id"] as string | undefined;
229	    const transport = await getOrCreateSession(sessionId);
230	
231	    if (!transport) {
232	      res.writeHead(404, { "Content-Type": "application/json" });
233	      res.end(JSON.stringify({ error: "Session not found" }));
234	      return;
235	    }
236	
237	    await transport.handleRequest(req, res);
238	    // Store new session after first request sets the session ID
239	    if (!sessionId && transport.sessionId) {
240	      sessions.set(transport.sessionId, transport);
241	    }
242	    return;
243	  }
244	
245	  res.writeHead(404, { "Content-Type": "application/json" });
246	  res.end(JSON.stringify({ error: "Not found" }));
247	});
