87	              ].join("\n");
88	            }
89	
90	            let approvalToken: string | undefined;
91	            if (preview.tier >= 2) {
92	              approvalToken = buildApprovalToken(config, command, preview.tier);
93	            }
94	
95	            const result = await nasExec(config, command, preview.tier, approvalToken, 90_000);
96	            const output = [result.stdout, result.stderr].filter(Boolean).join("\n");
97	            return `[${config.name}]\n${output || "(no output)"}`;
98	          } catch (err) {
99	            return `[${config.name}] Error: ${err instanceof Error ? err.message : String(err)}`;
100	          }
101	        }),
102	      );
103	
104	      return {
105	        content: [{ type: "text" as const, text: results.join("\n\n---\n\n") }],
106	      };
107	    });
108	  }
109	
110	  // run_command — free-form tier-1-only tool for deep ad-hoc diagnosis
111	  if (enabledRead.has("run_command")) {
112	    server.tool(
113	      "run_command",
114	      "Run any read-only shell command on a Synology NAS for deep diagnosis. Write commands are automatically blocked by the NAS API validator before execution.",
115	      {
116	        target: z
117	          .enum(["edgesynology1", "edgesynology2", "both"])
118	          .describe("Which NAS to run on"),
119	        command: z.string().describe("The shell command to execute"),
120	      },
121	      async ({ target, command }: { target: string; command: string }) => {
122	        const configs = getNasConfigs(target);
123	
124	        if (configs.length === 0) {
125	          return {
126	            content: [{ type: "text" as const, text: `No NAS configured for target "${target}".` }],
127	          };
128	        }
129	
130	        const results = await Promise.all(
131	          configs.map(async (config) => {
132	            try {
133	              const preview = await nasPreview(config, command);
134	              if (preview.blocked) {
135	                return `[${config.name}] Blocked: ${preview.summary}`;
136	              }
137	              if (preview.tier >= 2) {
138	                return `[${config.name}] This command requires write access and cannot be run via run_command. Add it to enabled_write_tools in tools-config.json, or use a specific write tool.`;
139	              }
140	              const result = await nasExec(config, command, 1, undefined, 90_000);
141	              const output = [result.stdout, result.stderr].filter(Boolean).join("\n");
142	              return `[${config.name}]\n${output || "(no output)"}`;
143	            } catch (err) {
144	              return `[${config.name}] Error: ${err instanceof Error ? err.message : String(err)}`;
145	            }
146	          }),
147	        );
148	
149	        return {
150	          content: [{ type: "text" as const, text: results.join("\n\n---\n\n") }],
151	        };
152	      },
153	    );
154	  }
155	
156	  return server;
157	}
158	
159	// ─── Session management ───────────────────────────────────────────────────────
160	
161	// Each MCP session gets its own transport + server pair.
162	const sessions = new Map<string, StreamableHTTPServerTransport>();
163	
164	async function getOrCreateSession(
165	  sessionId: string | undefined,
166	): Promise<StreamableHTTPServerTransport | null> {
167	  if (sessionId) {
168	    return sessions.get(sessionId) ?? null;
169	  }
170	  // New session
171	  const transport = new StreamableHTTPServerTransport({
172	    sessionIdGenerator: () => randomUUID(),
173	  });
174	  const mcpServer = createMcpServer();
175	  await mcpServer.connect(transport);
176	  transport.onclose = () => {
177	    if (transport.sessionId) sessions.delete(transport.sessionId);
178	  };
179	  if (transport.sessionId) {
180	    sessions.set(transport.sessionId, transport);
181	  }
182	  return transport;
183	}
184	
185	// ─── HTTP server ──────────────────────────────────────────────────────────────
186	
187	function isAuthorized(req: { headers: { authorization?: string } }): boolean {
188	  if (!BEARER_TOKEN) return true;
189	  return req.headers.authorization === `Bearer ${BEARER_TOKEN}`;
190	}
191	
192	const httpServer = createServer(async (req, res) => {
193	  res.setHeader("Access-Control-Allow-Origin", "*");
194	  res.setHeader("Access-Control-Allow-Methods", "GET, POST, DELETE, OPTIONS");
195	  res.setHeader("Access-Control-Allow-Headers", "Authorization, Content-Type, Mcp-Session-Id");
196	
197	  if (req.method === "OPTIONS") {
198	    res.writeHead(204);
199	    res.end();
200	    return;
201	  }
202	
203	  const url = new URL(req.url ?? "/", `http://localhost`);
204	
205	  // Health check — no auth required
206	  if (url.pathname === "/health" && req.method === "GET") {
207	    res.writeHead(200, { "Content-Type": "application/json" });
208	    res.end(
209	      JSON.stringify({
210	        status: "ok",
211	        service: "nas-mcp",
212	        sessions: sessions.size,
213	        read_tools: enabledRead.size,
214	        write_tools: enabledWrite.size,
215	      }),
216	    );
217	    return;
218	  }
219	
220	  if (!isAuthorized(req as Parameters<typeof isAuthorized>[0])) {
221	    res.writeHead(401, { "Content-Type": "application/json" });
222	    res.end(JSON.stringify({ error: "Unauthorized" }));
223	    return;
224	  }
225	
226	  // MCP endpoint — handles both Streamable HTTP (POST/GET) and session routing
227	  if (url.pathname === "/sse" || url.pathname === "/mcp") {
228	    const sessionId = req.headers["mcp-session-id"] as string | undefined;
229	    const transport = await getOrCreateSession(sessionId);
230	
231	    if (!transport) {
232	      res.writeHead(404, { "Content-Type": "application/json" });
233	      res.end(JSON.stringify({ error: "Session not found" }));
234	      return;
235	    }
236	
237	    await transport.handleRequest(req, res);
238	    // Store new session after first request sets the session ID
239	    if (!sessionId && transport.sessionId) {
240	      sessions.set(transport.sessionId, transport);
241	    }
242	    return;
243	  }
244	
245	  res.writeHead(404, { "Content-Type": "application/json" });
246	  res.end(JSON.stringify({ error: "Not found" }));
247	});
248	
249	httpServer.listen(PORT, () => {
250	  console.log(`NAS MCP server listening on port ${PORT}`);
251	  console.log(`Read tools: ${[...enabledRead].join(", ")}`);
252	  console.log(`Write tools: ${[...enabledWrite].join(", ") || "(none)"}`);
253	});

