try {
    $headers = @{ "Authorization" = "Bearer 14cde11e584136b15306c03d160ce9536da4f87f82d74c6d728a6c8cb6dd2122" }
    $response = Invoke-WebRequest -Uri "https://nas-mcp.designflow.app/mcp" -Headers $headers -Method POST -ContentType "application/json" -Body '{"jsonrpc":"2.0","id":1,"method":"initialize","params":{"protocolVersion":"2024-11-05","capabilities":{},"clientInfo":{"name":"test","version":"1.0"}}}' -UseBasicParsing -TimeoutSec 10
    Write-Host "MCP HTTP status: $($response.StatusCode)"
    Write-Host "MCP response: $($response.Content | ConvertFrom-Json | ConvertTo-Json -Depth 3)"
} catch {
    Write-Host "Error: $($_.Exception.Message)"
    if ($_.Exception.Response) {
        $reader = [System.IO.StreamReader]::new($_.Exception.Response.GetResponseStream())
        Write-Host "Body: $($reader.ReadToEnd())"
    }
}

# 406 is expected for MCP - it means the server is up and responding, 
# it just needs the proper Accept header for SSE or a full MCP client handshake
# The /sse endpoint is what mcp-remote uses
try {
    $headers = @{ 
        "Authorization" = "Bearer 14cde11e584136b15306c03d160ce9536da4f87f82d74c6d728a6c8cb6dd2122"
        "Accept" = "text/event-stream,application/json"
        "Content-Type" = "application/json"
    }
    $response = Invoke-WebRequest -Uri "https://nas-mcp.designflow.app/sse" -Headers $headers -Method GET -UseBasicParsing -TimeoutSec 5
    Write-Host "SSE HTTP status: $($response.StatusCode)"
    Write-Host "SSE Content-Type: $($response.Headers['Content-Type'])"
} catch {
    Write-Host "Status: $($_.Exception.Response.StatusCode.value__)"
    Write-Host "Error: $($_.Exception.Message)"
}

